parameters.task:
Evaluate this prompt:

{{ $json.prompt }}

Test utterances to simulate:
{{ json_stringify($json.test_utterances) }}

parameters.outputSchema:
{
  "type": "object",
  "properties": {
    "scores": {
      "type": "object",
      "properties": {
        "clarity": {
          "type": "number",
          "description": "0-100 from structural linguist"
        },
        "completeness": {
          "type": "number",
          "description": "0-100 from context auditor"
        },
        "precision": {
          "type": "number",
          "description": "0-100 from domain specialist"
        },
        "simulation_pass_rate": {
          "type": "number",
          "description": "0-100 pass rate"
        },
        "overall": {
          "type": "number",
          "description": "weighted average"
        }
      }
    },
    "structure_evaluation": {
      "type": "object",
      "properties": {
        "format": {
          "type": "string",
          "enum": [
            "structured",
            "semi-structured",
            "unstructured"
          ]
        },
        "has_sections": {
          "type": "boolean"
        },
        "has_bullet_points": {
          "type": "boolean"
        },
        "has_numbered_steps": {
          "type": "boolean"
        },
        "has_examples": {
          "type": "boolean"
        },
        "has_persona": {
          "type": "boolean"
        },
        "has_output_format": {
          "type": "boolean"
        },
        "has_constraints": {
          "type": "boolean"
        },
        "has_edge_cases": {
          "type": "boolean"
        },
        "word_count": {
          "type": "number"
        },
        "estimated_token_count": {
          "type": "number"
        },
        "information_density": {
          "type": "string",
          "enum": [
            "sparse",
            "moderate",
            "dense"
          ]
        },
        "readability": {
          "type": "string",
          "enum": [
            "easy",
            "moderate",
            "complex"
          ]
        },
        "verdict": {
          "type": "string"
        }
      }
    },
    "analysis": {
      "type": "object",
      "properties": {
        "structural_linguist": {
          "type": "object",
          "description": "Full output from structural linguist skill"
        },
        "context_auditor": {
          "type": "object",
          "description": "Full output from context auditor skill"
        },
        "domain_specialist": {
          "type": "object",
          "description": "Full output from domain specialist skill"
        },
        "theory_vs_practice": {
          "type": "string"
        }
      }
    },
    "simulation": {
      "type": "object",
      "properties": {
        "utterance_results": {
          "type": "array",
          "items": {
            "type": "object",
            "properties": {
              "utterance": {
                "type": "string"
              },
              "output": {
                "type": "string"
              },
              "on_topic": {
                "type": "boolean"
              },
              "format_match": {
                "type": "boolean"
              },
              "refusal": {
                "type": "boolean"
              },
              "quality_rating": {
                "type": "number"
              },
              "issues": {
                "type": "array",
                "items": {
                  "type": "string"
                }
              }
            }
          }
        },
        "pass_count": {
          "type": "number"
        },
        "fail_count": {
          "type": "number"
        },
        "overall_issues": {
          "type": "array",
          "items": {
            "type": "string"
          }
        }
      }
    },
    "issues": {
      "type": "array",
      "description": "Deduplicated master issue list from all analysts",
      "items": {
        "type": "object",
        "properties": {
          "issue": {
            "type": "string"
          },
          "severity": {
            "type": "string",
            "enum": [
              "critical",
              "major",
              "minor",
              "suggestion"
            ]
          },
          "source": {
            "type": "string"
          },
          "quote": {
            "type": "string"
          },
          "fix": {
            "type": "string"
